-- ── RECALCULAR PUNTOS ─────────────────────────────────────────
-- Ejecutar esta función por cada partido finalizado para calcular los puntos
-- NOTA: set_result() requiere auth admin. Usar la función interna directamente:

DO $$
DECLARE
  v_match matches%ROWTYPE;
  v_pred  predictions%ROWTYPE;
  v_exact BOOLEAN;
  v_correct BOOLEAN;
  v_pts INT;
BEGIN
  FOR v_match IN SELECT * FROM matches WHERE status = 'FINALIZADO' LOOP
    FOR v_pred IN SELECT * FROM predictions WHERE match_id = v_match.id LOOP
      v_exact := (v_pred.home_goals = v_match.home_goals AND v_pred.away_goals = v_match.away_goals);
      v_correct := (
        CASE WHEN v_pred.home_goals > v_pred.away_goals THEN 'home'
             WHEN v_pred.away_goals > v_pred.home_goals THEN 'away'
             ELSE 'draw' END
        = v_match.winner_side);
      IF v_exact THEN
        v_pts := CASE v_match.phase
          WHEN 'Grupos' THEN 2 WHEN '16avos' THEN 3 WHEN '8vos' THEN 3
          WHEN '4tos' THEN 4 WHEN 'Semis' THEN 5 WHEN '3er lugar' THEN 5
          WHEN 'Final' THEN 6 END;
      ELSIF v_correct THEN
        v_pts := CASE v_match.phase
          WHEN 'Grupos' THEN 1 WHEN '16avos' THEN 1 WHEN '8vos' THEN 1
          WHEN '4tos' THEN 2 WHEN 'Semis' THEN 3 WHEN '3er lugar' THEN 3
          WHEN 'Final' THEN 4 END;
      ELSE v_pts := 0;
      END IF;
      UPDATE predictions SET points = v_pts, is_exact = v_exact WHERE id = v_pred.id;
    END LOOP;
  END LOOP;
END;
$$;

